+namespace Microsoft.Integration.Shopify.Test;
+
+using Microsoft.Integration.Shopify;
+using Microsoft.Sales.History;
+using System.TestLibraries.Utilities;
+
+codeunit 139614 "Shpfy Shipping 3rdParty Test"
+{
+    Subtype = Test;
+    TestType = IntegrationTest;
+    TestPermissions = Disabled;
+    TestHttpRequestPolicy = BlockOutboundRequests;
+
+    var
+        Shop: Record "Shpfy Shop";
+        Any: Codeunit Any;
+        LibraryAssert: Codeunit "Library Assert";
+        InitializeTest: Codeunit "Shpfy Initialize Test";
+        IsInitialized: Boolean;
+
+    [Test]
+    procedure ExportShipmentSkips3rdPartyFulfillmentService()
+    var
+        ShopLocation: Record "Shpfy Shop Location";
+        SalesShipmentHeader: Record "Sales Shipment Header";
+        FulfillmentOrderHeader: Record "Shpfy FulFillment Order Header";
+        ExportShipments: Codeunit "Shpfy Export Shipments";
+        ShippingHelper: Codeunit "Shpfy Shipping Helper";
+        DeliveryMethodType: Enum "Shpfy Delivery Method Type";
+        FulfillmentRequests: List of [Text];
+        AssignedFulfillmentOrderIds: Dictionary of [BigInteger, Code[20]];
+        ShopifyOrderId: BigInteger;
+        LocationId: BigInteger;
+    begin
+        // [SCENARIO] Export shipment should skip fulfillment orders associated with 3rd party fulfillment services
+        // [GIVEN] A Shopify order fulfilled by a 3rd party fulfillment service location
+        Initialize();
+        LocationId := Any.IntegerInRange(10000, 99999);
+        DeliveryMethodType := DeliveryMethodType::Shipping;
+
+        // Create a shop location that is a 3rd party fulfillment service
+        ShopLocation.Init();
+        ShopLocation."Shop Code" := Shop.Code;
+        ShopLocation.Id := LocationId;
+        ShopLocation."Is Fulfillment Service" := true;
+        ShopLocation.Name := '3rd Party Fulfillment';
+        ShopLocation.Insert();
+
+        ShopifyOrderId := ShippingHelper.CreateRandomShopifyOrder(LocationId, DeliveryMethodType);
+        FulfillmentOrderHeader := ShippingHelper.CreateShopifyFulfillmentOrder(ShopifyOrderId, DeliveryMethodType);
+        ShippingHelper.CreateRandomSalesShipment(SalesShipmentHeader, ShopifyOrderId);
+
+        // [WHEN] Invoke the function CreateFulfillmentOrderRequest()
+        FulfillmentRequests := ExportShipments.CreateFulfillmentOrderRequest(SalesShipmentHeader, Shop, LocationId, DeliveryMethodType, AssignedFulfillmentOrderIds);
+
+        // [THEN] No fulfillment requests should be generated because the order is associated with a 3rd party fulfillment service
+        LibraryAssert.AreEqual(0, FulfillmentRequests.Count, '3rd party fulfillment service orders should be skipped');
+    end;
+
+    local procedure Initialize()
+    var
+        CommunicationMgt: Codeunit "Shpfy Communication Mgt.";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryRandom: Codeunit "Library - Random";
+        AccessToken: SecretText;
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Shpfy Shipping 3rdParty Test");
+        ClearLastError();
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Shpfy Shipping 3rdParty Test");
+
+        LibraryRandom.Init();
+        Any.SetDefaultSeed();
+
+        IsInitialized := true;
+        Commit();
+
+        Shop := InitializeTest.CreateShop();
+        CommunicationMgt.SetTestInProgress(false);
+
+        AccessToken := LibraryRandom.RandText(20);
+        InitializeTest.RegisterAccessTokenForShop(Shop.GetStoreName(), AccessToken);
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Shpfy Shipping 3rdParty Test");
+    end;
+}
